@module sampleManager  src=sampleManager.lua  loc=438  sha=ec591ad  mode=chunk  self=sm
@deps fileOps, cm, ds

# Invariants & contracts
  @invariant  ds is sole authority for slot state ({path,start,end,name}); JSFX is a pure consumer  @ 4
  @invariant  ds holds project-relative paths; sm prepends currentPrefix so JSFX needs no prefix  @ 5
  @invariant  gmem layout mirrors Continuum_Sampler.jsfx; SLOT_BASE/BOOT_BASE constants must stay in lockstep with the JSFX side  @ 6
  @invariant  per-instance bundled mailbox at SLOT_BASE+id*SLOT_STRIDE; preview retains its own legacy magic-gated mailbox at PREVIEW_BASE  @ 7
  @invariant  at most one slot drained per track per tick — keeps last-write-wins consolidation simple  @ 8
  @invariant  instance ids are persisted via track P_EXT (PEXT_KEY) and mirrored into JSFX slider2 every getInstanceId call  @ 9
  @invariant  boot-token watcher (BOOT_BASE+id) detects fresh JSFX mem[] (project reload, recompile) and triggers full rehydrate  @ 10
  @invariant  JSFX user-string slot cap is 1023; PATH_MAX (1019) + SLOT_STRIDE bookkeeping must not push slot string writes past that ceiling  @ 11

# Shapes
  @shape  slotEntry      = { path=string?, name=string?, start=number, ['end']=number }   -- ds-stored, path is project-relative  @ 12
  @shape  pendingEntry   = { slot=number, op=0|1, path=string?, name=string?, start=number?, ['end']=number? }  -- mailbox queue entry; op=1 is clear  @ 13
  @shape  trackState     = { fxGuid=string?, instanceId=number?, lastBootToken=number, slotSeq=number, pending={byOrder={int,...}, bySlot={[slot]=pendingEntry}} }  @ 14
  @shape  mailboxHeader  = [seq, seq_ack, slot, op, start, end, pathLen, nameLen, <pathBytes...>, <nameBytes...>]   -- gmem words at SLOT_BASE+id*SLOT_STRIDE  @ 15

# Imports
  @require fs = 'fs'  @ 16

# Private state
  @state SAMPLER_FX = 'Continuum Sampler'  @ 18
  @state GMEM_NS = 'Continuum_sampler'  @ 19
  @state MAGIC = 1717658484  @ 20   -- 'CTML' as 32-bit ASCII
  @state MAX_INSTANCES = 128  @ 21
  @state N_SAMPLES = 64  @ 22
  @state PATH_MAX = 1019  @ 24
  @state NAME_MAX = 64  @ 25
  @state SLOT_STRIDE = 8 + PATH_MAX + NAME_MAX  @ 26   -- 1091
  @state PREVIEW_BASE = 1024  @ 28
  @state SLOT_BASE = 561152  @ 31
  @state BOOT_BASE = SLOT_BASE + MAX_INSTANCES * SLOT_STRIDE  @ 32   -- 700800
  @state PREVIEW_SLOT_IDX = N_SAMPLES  @ 34
  @state SLIDER_INSTANCE_ID = 1  @ 35   -- slider2 in JSFX = param index 1 (0-based)
  @state PEXT_KEY = 'P_EXT:samplerInstanceId'  @ 36
  @state sm = {}  @ 91
  @state trackStates = {}  @ 93
  @state currentPrefix = nil  @ 94

# Private functions
  @fn writePath(base, path)  @ 39-42
      @contract  writePath emits NUL-terminated bytes; caller must ensure base+#path is within the addressable string region  @ 38
  @fn findSamplerFx(track)  @ 44-50
  @fn forceAnticipativeFxOff(track)  @ 54-59
      -- Force anticipative FX off (I_PERFFLAGS bit 1): sampler must not render ahead
      -- of the play cursor. Applied once per track; re-applied when its FX GUID changes.
  @fn readInstanceId(track)  @ 62-67
      @contract  readInstanceId validates the P_EXT value into [0, MAX_INSTANCES); returns nil for missing/out-of-range/non-numeric  @ 61
  @fn gatherTakenIds(skipTrack)  @ 70-80
      @contract  gatherTakenIds skips skipTrack so a re-assignment of the same track doesn't see its own id as taken  @ 69
  @fn nextFreeId(taken)  @ 82-87
  @fn absFor(rel)  @ 96-100
  @fn ensureTrackState(track)  @ 101-110
  @fn relForSrc(srcBase, hash)  @ 112-118
  @fn setEntry(idx, fields)  @ 120-125
  @fn clearEntry(idx)  @ 127-131
  @fn pushSlot(state, slot, opts)  @ 135-155
      @contract  pushSlot merges into the existing pendingEntry for slot; op=1 (clear) wipes path/name/start/end; op=0 only overrides explicitly-passed fields  @ 133
      @contract  byOrder records first-seen slot only (no duplicate enqueue); merges into the existing bySlot entry to preserve drain ordering  @ 134
  @fn drain(state)  @ 160-190
      @contract  drain writes header words in order [slot, op, start, end, pathLen, nameLen, body...] then bumps seq last so JSFX only fires once the body is in  @ 157
      @contract  drain gates on seq == seq_ack at addr/addr+1 — JSFX must have consumed the prior write before the next one can land  @ 158
      @contract  drain is no-op while instanceId is nil (track lacks the FX) or queue is empty  @ 159

# Public API (sm:*)
  @api sm:isLive(track)  @ 192-194
  @api sm:getInstanceId(track)  @ 196-207
  @api sm:rehydrateTrack(track)  @ 209-223
  @api sm:syncSlot(track, slot)  @ 225-238
  @api sm:tick()  @ 243-274
      @contract  tick is the only caller of gmem_attach for the bundled mailbox path; coordinator must invoke per frame  @ 240
      @contract  tick reaps trackStates entries for tracks whose sampler FX has been removed (else closed-over state leaks)  @ 241
      @contract  first-sight FX-GUID binding does NOT reset state (lastBootToken=0 still triggers rehydrate via the boot-token branch)  @ 242
  -- cm-authoritative slot operations
  @api sm:assign(track, idx, srcPath)  @ 279-300
      @contract  assign hashes srcPath, copies into projectPath/Continuum/<stem>-<hash>.<ext> if missing, writes cm rel path, queues mailbox push; returns false if hash or copy fails  @ 278
  @api sm:loadSlot(track, slot, relPath)  @ 302-307
  @api sm:clearSlot(track, slot)  @ 309-313
  @api sm:setTrim(track, slot, startFrames, endFrames)  @ 316-322
      @contract  setTrim sends start/end without path/name; pathLen=0/nameLen=0 in the wire payload means "leave alone" on the JSFX side  @ 315
  @api sm:setName(track, slot, name)  @ 324-328
  @api sm:stageInto(track, idx, srcPath)  @ 330-340
  -- Preview + prefix
  @api sm:setPrefix(prefix)  @ 344-347
  @api sm:previewSlot(track, slot, bounds)  @ 351-360
      @contract  preview writes are silently dropped if the magic word at PREVIEW_BASE is non-zero (JSFX hasn't consumed the prior preview command)  @ 349
      @contract  preview header order: payload words first, magic last — JSFX dispatches on the MAGIC write  @ 350
  @api sm:stopPreview(track)  @ 363-371
      @contract  stopPreview encodes "stop" as slot=-1 in the same preview mailbox; same magic-gate as previewSlot  @ 362
  @api sm:previewPath(track, path)  @ 374-384
      @contract  previewPath uses the dedicated PREVIEW_SLOT_IDX (=N_SAMPLES) so the JSFX side knows to load from the inline path bytes rather than a slot  @ 373
  -- Track surface
  @api sm:listTracks()  @ 388-400
  @api sm:migrate(projectPath, oldProjectPath)  @ 405-422
      @contract  migrate iterates every sampler track via ds:getAt so non-bound tracks migrate too  @ 402
      @contract  ds rel paths are preserved across migrate; only file bytes move  @ 403
      @contract  migrate is a no-op if oldProjectPath is missing or unchanged  @ 404
  @api sm:watchPath()  @ 427-435
      @contract  watchPath calls setPrefix every call (idempotent)  @ 424
      @contract  migrate + cm.lastProjectPath write only on GetProjectPath change  @ 425
      @contract  cm.lastProjectPath persists at project-tier so close-during-save is caught next open  @ 426

